mapper.insert:

    select pj_seq.nextval from dual


DECLARE
    v_lft INTEGER;
    v_rgt INTEGER;
BEGIN



            SELECT prj_rgt INTO v_lft FROM project WHERE id = #{prjParId};
            UPDATE project SET prj_lft = prj_lft + 2 WHERE prj_lft >= v_lft;
            UPDATE project SET prj_rgt = prj_rgt + 2 WHERE prj_rgt >= v_lft;
            v_rgt := v_lft + 1;




            SELECT NVL(MAX(prj_rgt), 0) + 1 INTO v_lft FROM project;
            v_rgt := v_lft + 1;



    INSERT INTO project (
        id, biz_no, prj_par_id, prj_root_id, prj_name, 
        prj_desc, prj_identifier, prj_status_cd, prj_lft, prj_rgt, user_id
    ) VALUES (
        #{id}, #{bizNo}, #{prjParId}, 

            #{prjRootId}
            #{id} 
        , 
        #{prjName}, #{prjDesc}, #{prjIdentifier}, '01PROSTAT', 
        v_lft, v_rgt, #{userId}
    );



END;
